// flow/cli/src/emitBundle.js
/**
 * emitBundle.js â€” the referenceable ASSET BUNDLE emitter (spec Â§"deployable
 * flow collection" â†’ asset bundle).
 *
 * Pure: takes the in-memory collection and returns a path â†’ string map; writes
 * nothing (the orchestrator persists it). Emits three files:
 *
 *   flows.js  â€” `export const flows = { [key]: <normalized flow|flow-set object> }`
 *               as a stable, pretty JSON literal. Key order follows the
 *               collection's (sorted) insertion order, so the output is stable.
 *   index.js  â€” the PRE-WIRED renderer: imports mountFlowAuto from the renderer
 *               package and `flows` from ./flows.js, re-exports both, and adds a
 *               `mount(el, key, opts)` convenience. This is the bundle a
 *               downstream build imports.
 *   README.md â€” short usage.
 *
 * `rendererSpecifier` is the package name index.js imports the renderer from â€”
 * `ribbonflow` (the unscoped no-framework headline) by default; overridable so
 * a consumer can point it at `@ribbonflow/core` or a workspace link.
 */

/**
 * @param {{ flows: Record<string, { flow: object }> }} collection
 * @param {object} [opts]
 * @param {string} [opts.rendererSpecifier='ribbonflow']
 * @returns {{ files: { 'flows.js': string, 'index.js': string, 'README.md': string } }}
 */
export function emitBundle(collection, { rendererSpecifier = 'ribbonflow' } = {}) {
  const flowMap = {}
  for (const [key, entry] of Object.entries(collection.flows)) {
    flowMap[key] = entry.flow
  }

  const flowsJs =
    `// Generated by @flow-designer/cli â€” do not edit by hand.\n` +
    `// Each value is a normalized, render-ready flow (or flow-set) object.\n` +
    `export const flows = ${JSON.stringify(flowMap, null, 2)}\n`

  const indexJs =
    `// Generated by @flow-designer/cli â€” the pre-wired flow renderer.\n` +
    `import { mountFlowAuto } from '${rendererSpecifier}'\n` +
    `import { flows } from './flows.js'\n` +
    `\n` +
    `export { flows }\n` +
    `export { mountFlowAuto }\n` +
    `\n` +
    `/**\n` +
    ` * Mount a flow by key into a host element.\n` +
    ` * @param {Element} el\n` +
    ` * @param {string} key â€” a key from \`flows\`.\n` +
    ` * @param {object} [opts] â€” forwarded to mountFlowAuto (e.g. { showMetrics }).\n` +
    ` * @returns {{ update: Function, destroy: Function }}\n` +
    ` */\n` +
    `export function mount(el, key, opts) {\n` +
    `  return mountFlowAuto(el, flows[key], opts)\n` +
    `}\n`

  const keys = Object.keys(flowMap)
  const readme =
    `# Flow bundle\n\n` +
    `Generated by \`@flow-designer/cli\`. A pre-wired renderer over ${keys.length} ` +
    `flow${keys.length === 1 ? '' : 's'}.\n\n` +
    `## Usage\n\n` +
    '```js\n' +
    `import { mount, flows } from './index.js'\n\n` +
    `// flows is { [key]: normalized-flow-object }; mount renders one by key.\n` +
    `const handle = mount(document.getElementById('stage'), '${keys[0] ?? 'some/key'}')\n` +
    `// handle.update(flows['other/key']); handle.destroy()\n` +
    '```\n\n' +
    `The bundle imports its renderer from \`${rendererSpecifier}\`; provide that ` +
    `package (or an import-map/alias to it) in your build.\n\n` +
    `## Keys\n\n` +
    (keys.length ? keys.map((k) => `- \`${k}\``).join('\n') + '\n' : '_(none)_\n')

  return { files: { 'flows.js': flowsJs, 'index.js': indexJs, 'README.md': readme } }
}
